{{(() => {
    // Wir holen den Wert aus der Variable, nicht direkt aus der Query
    const end = variables.last_game_end;
    const now = Date.now();

    // Sicherheits-Check: Falls noch kein Wert gesetzt wurde oder 0 ist
    if (!end || end === 0 || !variables.game_started) {
        return "--:--";
    }

    const diff = end - now;

    // Wenn die Zeit abgelaufen ist
    if (diff <= 0) {
        return "0:00";
    }

    const minutes = Math.floor(diff / 1000 / 60);
    const seconds = Math.floor((diff / 1000) % 60);

    // Formatiert als "MM:SS min"
    return `${minutes}:${seconds < 10 ? '0' : ''}${seconds}`;
})()}}
